import{_ as a,o as i,c as e,a5 as n}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：UPS 模式状态机（UPS mode state machine）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：UPS 模式状态机（UPS mode state machine）","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0024-ups-mode-state-machine.html` 的源稿和补充资料，中文主讲。它只使用教学模型和教学参数，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据；学习记录中也不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。"},"headers":[],"relativePath":"content/power/concepts/embedded/ups-mode-state-machine.md","filePath":"content/power/concepts/embedded/ups-mode-state-machine.md","lastUpdated":null}'),t={name:"content/power/concepts/embedded/ups-mode-state-machine.md"};function l(p,s,h,o,d,c){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="概念-ups-模式状态机-ups-mode-state-machine" tabindex="-1">概念：UPS 模式状态机（UPS mode state machine） <a class="header-anchor" href="#概念-ups-模式状态机-ups-mode-state-machine" aria-label="Permalink to &quot;概念：UPS 模式状态机（UPS mode state machine）&quot;">​</a></h1><p>本页是 <code>lessons/0024-ups-mode-state-machine.html</code> 的源稿和补充资料，中文主讲。它只使用教学模型和教学参数，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据；学习记录中也不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>UPS 模式状态机（UPS mode state machine）是把不间断电源（uninterruptible power supply / UPS）的工作模式组织成明确状态和转换条件的软件结构。</p><p>本节只保留四个入门状态：</p><ul><li>在线模式（online mode）：市电正常，PFC 与逆变器供电。</li><li>电池模式（battery mode）：市电异常，电池经 DC-DC 支撑直流母线，逆变器供电。</li><li>旁路模式（bypass mode）：负载由旁路供电，逆变 PWM 关闭。</li><li>故障模式（fault mode）：危险条件锁存，输出许可关闭，等待复位条件。</li></ul><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>UPS 同时要处理市电、旁路、电池、逆变器、保护和通信。如果这些条件散落在很多 <code>if</code> 语句里，读 C 工程时很难判断系统现在“处于什么模式、允许什么输出、为什么不能切换”。</p><p>状态机（state machine）把模式、转换条件和输出许可放在一起，是阅读完整 UPS 工程代码的主干。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>状态机像列车调度。市电正常时走在线轨道；市电丢失时切到电池轨道；电池不足但旁路同步时切到旁路轨道；没有安全供电路径时进入故障轨道并锁住，不能靠瞬时信号自己跳回来。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if mode == ONLINE:</span></span>
<span class="line"><span>    if not mains_ok after delay:</span></span>
<span class="line"><span>        mode = BATTERY if battery_ok else BYPASS if bypass_sync else FAULT</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if mode == BATTERY:</span></span>
<span class="line"><span>    if battery_low:</span></span>
<span class="line"><span>        mode = BYPASS if bypass_sync else FAULT</span></span>
<span class="line"><span>    if mains_ok:</span></span>
<span class="line"><span>        mode = ONLINE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if mode == BYPASS:</span></span>
<span class="line"><span>    if mains_ok:</span></span>
<span class="line"><span>        mode = ONLINE</span></span>
<span class="line"><span>    if not bypass_sync and not battery_ok:</span></span>
<span class="line"><span>        mode = FAULT</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if mode == FAULT:</span></span>
<span class="line"><span>    outputs disabled until reset_request and safe input</span></span></code></pre></div><h2 id="_5-仿真观察" tabindex="-1">5. 仿真观察 <a class="header-anchor" href="#_5-仿真观察" aria-label="Permalink to &quot;5. 仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_mode_state_machine.py</span></span></code></pre></div><p>默认会生成并尝试自动打开：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/results/ups_mode_state_machine.png</span></span></code></pre></div><p>默认事件顺序：</p><ul><li>80 ms：市电丢失，延时后进入电池模式。</li><li>180 ms：电池不可用，若旁路同步则延时后进入旁路模式。</li><li>270 ms：逆变器故障且旁路已失去同步，进入故障模式。</li><li>380 ms：复位请求到来，市电已恢复，回到在线模式。</li></ul><p>一个仿真任务：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_mode_state_machine.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bypass</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sync-time</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.40</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bypass</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">loss</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">time </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.41</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\ups_mode_no_safe_bypass.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_mode_state_machine.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">transfer</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">delay </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.050</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\ups_mode_delay_50ms.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>第一条命令观察电池低且没有安全旁路时如何进入故障；第二条命令观察切换延时变长后，模式变化时刻如何推迟。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>真实 C 工程中可按这些模块找：</p><ul><li><code>mode_state_machine.c</code>：模式状态机和转换条件。</li><li><code>protection.c</code>：故障锁存（fault latch）与复位条件。</li><li><code>bypass_sync.c</code>：旁路同步许可。</li><li><code>pwm.c</code>：脉宽调制（pulse-width modulation / PWM）输出许可。</li><li><code>contactors.c</code>：旁路接触器、输入接触器和输出继电器命令。</li><li><code>communication.c</code>：把当前模式、故障码和许可状态上报。</li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>错误理解：模式切换就是把几个继电器打开或关闭。<br> 正确理解：继电器只是输出，背后要先满足输入条件、保护条件、同步条件和延时条件。</li><li>错误理解：故障消失就自动回在线。<br> 正确理解：严重故障通常需要故障锁存和明确复位请求。</li><li>错误理解：旁路同步只属于 PLL 课程。<br> 正确理解：PLL 提供相位信息，状态机决定能否真的切换供电路径。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释在线、电池、旁路、故障四个模式的区别。</li><li>能说明每个模式下 PFC、DC-DC、逆变 PWM、旁路接触器的许可状态。</li><li>能根据图指出市电丢失、电池低、旁路失步、逆变故障和复位请求各自造成的模式变化。</li><li>能基于图和脚本准备导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>默认仿真中，ONLINE、BATTERY、BYPASS、FAULT 分别出现在什么时间段？</li><li>为什么 BYPASS 模式下逆变 PWM 关闭，但旁路接触器打开？</li><li>为什么进入 FAULT 后不能因为市电恢复就立刻回 ONLINE？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>ups_mode_state_machine.py</code> 看到市电丢失后先进入电池模式，电池不可用且旁路同步后再进入旁路模式。公司工程里模式状态机一般由哪个模块负责？</li><li>我看到故障模式会关闭 PFC、DC-DC、逆变 PWM 和旁路接触器。真实产品里哪些故障会保留旁路供电，哪些故障会全关？</li><li>我在脚本里用了 <code>transfer delay=20 ms</code>。真实工程里模式切换延时通常来自继电器动作、静态开关时序，还是软件去抖？</li></ul>`,34)])])}const u=a(t,[["render",l]]);export{k as __pageData,u as default};
